  return (
    <div className="card">
      <div className="row" style={{ marginBottom: 12 }}>
        <input
          ref={inputRef}
          placeholder="Add todo..."
          onKeyDown={e => e.key === 'Enter' && addTodo()}
          style={{
            flex: 1, padding: '8px 12px', border: '1px solid #e2e8f0',
            borderRadius: 6, outline: 'none', fontSize: 14,
