                                        )}
                                    </div>
                                </BaseSelect.Popup>
                            </BaseSelect.Positioner>
                        </BaseSelect.Portal>
                    </BaseSelect.Root>

                    {/* Nút X đặt NGOÀI Trigger, absolute position — click không bubble lên Trigger */}
                    {clearable && selectedValue && (
                        <button
                            type="button"
                            aria-label={clearLabel}
                            onMouseDown={handleClear}
                            className="cursor-pointer absolute right-3 top-1/2 -translate-y-1/2 flex h-5 w-5 items-center justify-center rounded-full text-muted-foreground hover:bg-red-50 hover:text-red-500 transition-colors z-10"
                        >
                            <X className="h-3 w-3" />
                        </button>
                    )}
                </div>

                {description && !error && (
                    <p className="text-[0.8rem] text-muted-foreground">{description}</p>
                )}
                {error && (
                    <p className="text-[0.8rem] font-medium text-danger">{error}</p>
                )}
            </div>
        );
    }
);

Select.displayName = 'Select';

