        data-size={size}
        className={menuButtonVariants({ size, collapsed: isCollapsed, className })}
        {...props}
      >
        {isCollapsed
          ? React.Children.toArray(children)[0]
          : children}
      </button>
    );

    if (isCollapsed && tooltip) {
      return (
        <Tooltip>
          <TooltipTrigger render={button} />
          <TooltipContent side="right">{tooltip}</TooltipContent>
        </Tooltip>
      );
